static void rb_tb_serialize_u128(VALUE items_rb, uint8_t *buf, long count) {
    tb_uint128_t *ids = (tb_uint128_t *)buf;
    for (long i = 0; i < count; i++) {
        rb_tb_pack_u128(RARRAY_AREF(items_rb, i), &ids[i]);
    }
}

static size_t rb_tb_event_size(TB_OPERATION operation) {
    switch (operation) {
    case TB_OPERATION_LOOKUP_ACCOUNTS:
        return sizeof(tb_uint128_t);
    case TB_OPERATION_LOOKUP_TRANSFERS:
        return sizeof(tb_uint128_t);
    case TB_OPERATION_GET_ACCOUNT_TRANSFERS:
        return sizeof(tb_account_filter_t);
    case TB_OPERATION_GET_ACCOUNT_BALANCES:
        return sizeof(tb_account_filter_t);
    case TB_OPERATION_QUERY_ACCOUNTS:
        return sizeof(tb_query_filter_t);
    case TB_OPERATION_QUERY_TRANSFERS:
        return sizeof(tb_query_filter_t);
    case TB_OPERATION_CREATE_ACCOUNTS:
        return sizeof(tb_account_t);
    case TB_OPERATION_CREATE_TRANSFERS:
        return sizeof(tb_transfer_t);
    default:
        rb_raise(rb_eRuntimeError, "unsupported operation: %d", (int)operation);
        return 0;
    }
}

static void rb_tb_serialize(
    TB_OPERATION operation,
    VALUE items_rb,
    uint8_t *buf,
    long count
) {
    switch (operation) {
    case TB_OPERATION_LOOKUP_ACCOUNTS:
        rb_tb_serialize_u128(items_rb, buf, count);
        break;
    case TB_OPERATION_LOOKUP_TRANSFERS:
        rb_tb_serialize_u128(items_rb, buf, count);
        break;
    case TB_OPERATION_GET_ACCOUNT_TRANSFERS:
        rb_tb_serialize_get_account_transfers(items_rb, buf, count);
        break;
    case TB_OPERATION_GET_ACCOUNT_BALANCES:
        rb_tb_serialize_get_account_balances(items_rb, buf, count);
        break;
    case TB_OPERATION_QUERY_ACCOUNTS:
        rb_tb_serialize_query_accounts(items_rb, buf, count);
        break;
    case TB_OPERATION_QUERY_TRANSFERS:
        rb_tb_serialize_query_transfers(items_rb, buf, count);
        break;
    case TB_OPERATION_CREATE_ACCOUNTS:
        rb_tb_serialize_create_accounts(items_rb, buf, count);
        break;
    case TB_OPERATION_CREATE_TRANSFERS:
        rb_tb_serialize_create_transfers(items_rb, buf, count);
        break;
    default:
        rb_raise(rb_eRuntimeError, "unsupported operation: %d", (int)operation);
    }
}

static VALUE rb_tb_deserialize(
    TB_OPERATION operation,
    const uint8_t *buf,
    uint32_t buf_size
) {
    switch (operation) {
    case TB_OPERATION_LOOKUP_ACCOUNTS:
        return rb_tb_deserialize_lookup_accounts(buf, buf_size);
    case TB_OPERATION_LOOKUP_TRANSFERS:
        return rb_tb_deserialize_lookup_transfers(buf, buf_size);
    case TB_OPERATION_GET_ACCOUNT_TRANSFERS:
        return rb_tb_deserialize_get_account_transfers(buf, buf_size);
    case TB_OPERATION_GET_ACCOUNT_BALANCES:
        return rb_tb_deserialize_get_account_balances(buf, buf_size);
    case TB_OPERATION_QUERY_ACCOUNTS:
        return rb_tb_deserialize_query_accounts(buf, buf_size);
    case TB_OPERATION_QUERY_TRANSFERS:
        return rb_tb_deserialize_query_transfers(buf, buf_size);
    case TB_OPERATION_CREATE_ACCOUNTS:
        return rb_tb_deserialize_create_accounts(buf, buf_size);
    case TB_OPERATION_CREATE_TRANSFERS:
        return rb_tb_deserialize_create_transfers(buf, buf_size);
    default:
        rb_raise(rb_eRuntimeError, "unsupported operation: %d", (int)operation);
    }
}
